<?php declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('orders.view');$id=cmsId($_GET['id']??0);$pdo=obtenerConexion();$q=$pdo->prepare('SELECT p.*,u.nombre,u.apellido,u.correo FROM pedidos p JOIN usuarios u ON u.id=p.usuario_id WHERE p.id=:id');$q->execute(['id'=>$id]);$p=$q->fetch();if(!$p){cmsFlash('error','Pedido no encontrado.');header('Location:index.php');exit;}$q=$pdo->prepare('SELECT * FROM pedido_detalles WHERE pedido_id=:id');$q->execute(['id'=>$id]);$det=$q->fetchAll();$q=$pdo->prepare('SELECT * FROM pedido_historial WHERE pedido_id=:id ORDER BY created_at');$q->execute(['id'=>$id]);$hist=$q->fetchAll();cmsCabecera('Pedido '.$p['numero'],'pedidos/index.php');?><div class="row"><div class="col-lg-8"><div class="card card-rounded"><div class="card-body"><h2 class="h5">Productos</h2><div class="table-responsive"><table class="table"><thead><tr><th>Producto</th><th>Cantidad</th><th>Precio aplicado</th><th>Descuento</th><th>Subtotal</th></tr></thead><tbody><?php foreach($det as$d):?><tr><td><?=atenea_e($d['nombre_producto'])?><small class="d-block"><?=atenea_e((string)$d['sku'])?></small></td><td><?=$d['cantidad']?></td><td>$<?=number_format((float)$d['precio_unitario'],2)?></td><td>$<?=number_format((float)$d['descuento_unitario'],2)?></td><td>$<?=number_format((float)$d['subtotal'],2)?></td></tr><?php endforeach;?></tbody></table></div><h2 class="h5 mt-4">Historial</h2><?php foreach($hist as$h):?><div class="border-bottom py-2"><strong><?=atenea_e($h['estado_nuevo'])?></strong> · <?=date('d/m/Y H:i',strtotime($h['created_at']))?><small class="d-block text-muted"><?=atenea_e((string)$h['nota'])?></small></div><?php endforeach;?></div></div></div><div class="col-lg-4"><div class="card card-rounded"><div class="card-body"><h2 class="h5">Resumen</h2><p><strong>Cliente:</strong><br><?=atenea_e(trim($p['nombre'].' '.$p['apellido']))?><br><?=atenea_e($p['correo'])?></p><p><strong>Estado:</strong> <?=atenea_e($p['estado'])?></p><p><strong>Total:</strong> $<?=number_format((float)$p['total'],2)?> <?=strtoupper($p['moneda'])?></p><p><strong>Checkout:</strong><br><small><?=atenea_e((string)$p['stripe_checkout_session_id'])?></small></p><p><strong>Payment Intent:</strong><br><small><?=atenea_e((string)$p['stripe_payment_intent_id'])?></small></p><h2 class="h5 mt-4">Actualizar estado</h2><form method="post" action="estado.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$id?>"><select class="form-select mb-2" name="estado" required><option value="">Selecciona</option><?php foreach(['preparando','enviado','entregado','cancelado','reembolsado'] as$e):?><option value="<?=$e?>"><?=$e?></option><?php endforeach;?></select><textarea class="form-control mb-2" name="nota" maxlength="500" placeholder="Observación"></textarea><button class="btn btn-primary mb-2">Registrar cambio</button></form><a class="btn btn-light" href="index.php">Volver</a></div></div></div></div><?php cmsPie();?>
